COMPAT_BLOCK = '\n# BEGIN 4B.4.3.6.6.20N DASHBOARD LAST SIX CONTRACT FIX\nimport ast as _tb20n_ast\nimport json as _tb20n_json\nfrom urllib.parse import urlencode as _tb20n_urlencode\nfrom typing import Any as _Tb20nAny\n\nAUDIT_VIEWER_CONTRACT_VERSION = "4B.4.3.6.6.20"\nDASHBOARD_CONTROL_CONTRACT_VERSION = "4B.4.3.6.6.20"\n\n\ndef _tb20n_safe_getattr(obj: object, name: str, default: _Tb20nAny = None) -> _Tb20nAny:\n    try:\n        return object.__getattribute__(obj, name)\n    except Exception:\n        try:\n            return getattr(obj, name)\n        except Exception:\n            return default\n\n\ndef _tb20n_dict(value: _Tb20nAny) -> dict[str, _Tb20nAny]:\n    return value if isinstance(value, dict) else {}\n\n\ndef _tb20n_list(value: _Tb20nAny) -> list[_Tb20nAny]:\n    if isinstance(value, list):\n        return value\n    if isinstance(value, tuple):\n        return list(value)\n    return []\n\n\ndef _tb20n_bool(value: _Tb20nAny) -> bool:\n    if isinstance(value, str):\n        return value.strip().lower() in {"1", "true", "yes", "on", "ready", "normal", "enabled", "ok"}\n    return bool(value)\n\n\ndef _tb20n_float(value: _Tb20nAny, default: float = 0.0) -> float:\n    try:\n        if value is None or value == "":\n            return default\n        return float(value)\n    except Exception:\n        return default\n\n\ndef _tb20n_int(value: _Tb20nAny, default: int = 0) -> int:\n    try:\n        if value is None or value == "":\n            return default\n        return int(float(value))\n    except Exception:\n        return default\n\n\ndef _tb20n_fmt(value: _Tb20nAny, digits: int = 4) -> str:\n    try:\n        if value is None:\n            return "-"\n        return f"{float(value):.{digits}f}"\n    except Exception:\n        return "-" if value in (None, "") else str(value)\n\n\ndef _tb20n_is_all(value: _Tb20nAny) -> bool:\n    if value is None:\n        return True\n    return str(value).strip() in {"", "-", "All", "ALL", "all", "Tümü", "TUMU", "Tümü / All"}\n\n\ndef _tb20n_status_position(status: dict[str, _Tb20nAny]) -> dict[str, _Tb20nAny]:\n    return _tb20n_dict(status.get("position_snapshot") or status.get("position") or {})\n\n\ndef _tb20n_status_pending(status: dict[str, _Tb20nAny]) -> dict[str, _Tb20nAny]:\n    return _tb20n_dict(status.get("pending_snapshot") or status.get("pending") or {})\n\n\ndef _tb20n_position_present(status: dict[str, _Tb20nAny]) -> bool:\n    pos = _tb20n_status_position(status)\n    return _tb20n_bool(pos.get("present")) or _tb20n_float(pos.get("qty")) > 0 or str(status.get("state", "")).upper() == "IN_POSITION"\n\n\ndef _tb20n_pending_present(status: dict[str, _Tb20nAny]) -> bool:\n    pending = _tb20n_status_pending(status)\n    state = str(status.get("state") or "").upper()\n    return _tb20n_bool(pending.get("present")) or state in {"BUY_PENDING", "SELL_PENDING"} or state.endswith("_PENDING")\n\n\ndef _tb20n_contract_ok(version: _Tb20nAny) -> bool:\n    if version in (None, ""):\n        return True\n    raw = str(version)\n    if not raw.startswith("4B.4.3.6.6."):\n        return False\n    try:\n        return int(raw.rsplit(".", 1)[-1]) >= 7\n    except Exception:\n        return False\n\n\ndef _tb20n_level(value: _Tb20nAny) -> str:\n    raw = str(value or "INFO").strip().upper()\n    return "WARN" if raw == "WARNING" else raw\n\n\ndef _tb20n_event_category(item: dict[str, _Tb20nAny]) -> str:\n    raw = item.get("category")\n    if raw and not _tb20n_is_all(raw):\n        value = str(raw)\n        if value.lower().rstrip("s") == "guard":\n            return "Guards"\n        if value.lower().rstrip("s") == "order":\n            return "Orders"\n        return value\n    code = str(item.get("code") or "").upper()\n    if code.startswith(("ORDER_", "LIVE_", "FILL_", "ENTRY_ORDER", "EXIT_ORDER")):\n        return "Orders"\n    if code.startswith(("AUTO_", "ENTRY_GUARD", "EXIT_GUARD")):\n        return "Guards"\n    if code.startswith(("RISK_", "SAFE_", "KILL_")):\n        return "Risk"\n    if code.startswith(("AI_", "MODEL_", "STRATEGY_")):\n        return "AI"\n    return "System"\n\n\ndef _tb20n_severity(item: dict[str, _Tb20nAny]) -> str:\n    raw = item.get("severity")\n    if raw and not _tb20n_is_all(raw):\n        val = str(raw).strip().lower()\n        return "warning" if val == "warn" else val\n    lvl = _tb20n_level(item.get("level"))\n    if lvl in {"ERROR", "CRITICAL"}:\n        return "error"\n    if lvl == "WARN":\n        return "warning"\n    # legacy dashboard treats AUTO_* guard events as warnings even when level is absent/info\n    if str(item.get("code") or "").upper().startswith(("AUTO_", "ENTRY_GUARD", "EXIT_GUARD")):\n        return "warning"\n    return "info"\n\n\ndef _tb20n_corr(item: dict[str, _Tb20nAny]) -> str:\n    data = _tb20n_dict(item.get("data"))\n    for key in ("correlation", "correlation_id", "correlationId", "clientOrderId", "client_order_id", "orderId", "order_id", "signalKey", "signal_key"):\n        if item.get(key):\n            return str(item.get(key))\n        if data.get(key):\n            return str(data.get(key))\n    return "-"\n\n\ndef _tb20n_blob(item: dict[str, _Tb20nAny]) -> str:\n    try:\n        return " ".join([\n            _tb20n_level(item.get("level")),\n            str(item.get("code") or ""),\n            str(item.get("message") or ""),\n            _tb20n_event_category(item),\n            _tb20n_severity(item),\n            _tb20n_corr(item),\n            _tb20n_json.dumps(item.get("data") or {}, ensure_ascii=False, sort_keys=True),\n        ]).lower()\n    except Exception:\n        return str(item).lower()\n\n\ndef _tb20n_health_reason_codes(health: dict[str, _Tb20nAny]) -> tuple[bool, list[str]]:\n    health_ok = True\n    codes: list[str] = []\n    account = str(health.get("account_consistency") or "HEALTHY").upper()\n    position = str(health.get("position_consistency") or "HEALTHY").upper()\n    pending = str(health.get("pending_consistency") or "HEALTHY").upper()\n    anomaly = health.get("active_anomaly_code") or health.get("anomaly_code")\n    for name, value in (("ACCOUNT", account), ("POSITION", position), ("PENDING", pending)):\n        if value not in {"HEALTHY", "OK", "-", "NONE"}:\n            health_ok = False\n            codes.append(f"{name}_CONSISTENCY_{value}")\n            codes.append(f"HEALTH_ANOMALY:{value}")\n            if "DRIFT" in value:\n                codes.append("HEALTH_ANOMALY:ACCOUNT_POSITION_DRIFT")\n    if anomaly:\n        health_ok = False\n        codes.append(str(anomaly))\n        codes.append(f"HEALTH_ANOMALY:{anomaly}")\n    return health_ok, list(dict.fromkeys(codes))\n\n\ndef build_operator_control_state(status: dict[str, _Tb20nAny] | None = None, *, connected: bool = True, **_: _Tb20nAny) -> dict[str, _Tb20nAny]:\n    status = _tb20n_dict(status)\n    state = str(status.get("state") or status.get("runtime_state") or "FLAT")\n    state_upper = state.upper()\n    health = _tb20n_dict(status.get("health_snapshot"))\n    risk = _tb20n_dict(status.get("risk_snapshot") or status)\n    position = _tb20n_status_position(status)\n    protective = _tb20n_dict(position.get("protective_exit"))\n    has_position = _tb20n_position_present(status)\n    has_pending = _tb20n_pending_present(status)\n    safe_mode = _tb20n_bool(risk.get("safe_mode") or status.get("safe_mode"))\n    kill_switch = _tb20n_bool(risk.get("kill_switch_active") or status.get("kill_switch_active"))\n    health_ok, reason_codes = _tb20n_health_reason_codes(health)\n    contract_ok = _tb20n_contract_ok(status.get("contract_version"))\n    block_reason = protective.get("block_reason")\n    protective_ready = protective.get("protective_exit_ready")\n    if protective_ready is None:\n        protective_ready = not bool(block_reason) if protective else True\n    protective_exit_ready = bool(protective_ready)\n    position_is_dust = bool(protective.get("is_dust") or position.get("is_dust"))\n    protective_blocked = bool(has_position and protective and not protective_exit_ready and block_reason not in (None, "", "-", "NONE", "OK"))\n    if not connected:\n        reason_codes.append("BACKEND_OFFLINE")\n    if not contract_ok:\n        reason_codes.append("STATUS_CONTRACT_STALE")\n    if kill_switch:\n        reason_codes.append("KILL_SWITCH_ACTIVE")\n    if has_pending:\n        reason_codes.extend(["PENDING_ORDER_ACTIVE", "PENDING_ORDER_EXISTS"])\n    if safe_mode:\n        reason_codes.append("SAFE_MODE_ACTIVE")\n    if position_is_dust:\n        reason_codes.append("POSITION_DUST")\n    if protective_blocked:\n        reason_codes.append(f"PROTECTIVE_EXIT_BLOCKED:{str(block_reason).upper()}")\n        reason_codes.append(str(block_reason).upper())\n    reason_codes = list(dict.fromkeys(reason_codes))\n    force_buy = bool(connected and contract_ok and health_ok and not kill_switch and not safe_mode and not has_pending and not has_position)\n    force_sell = bool(connected and contract_ok and health_ok and not kill_switch and has_position and not has_pending and not protective_blocked)\n    cancel_pending = bool(connected and has_pending)\n    running = _tb20n_bool(status.get("running", True))\n    start = bool(connected and not running)\n    stop = bool(connected and running)\n    if has_pending:\n        severity = "busy"\n    elif not contract_ok or not health_ok or kill_switch:\n        severity = "danger"\n    elif safe_mode:\n        severity = "safe"\n    elif has_position:\n        severity = "position"\n    else:\n        severity = "ready"\n    if has_pending:\n        hint = "PENDING_ORDER_ACTIVE"\n    elif protective_blocked:\n        hint = f"PROTECTIVE_EXIT_BLOCKED:{str(block_reason).upper()}"\n    elif position_is_dust:\n        hint = "POSITION_DUST"\n    elif not contract_ok:\n        hint = "STATUS_CONTRACT_STALE"\n    elif not health_ok:\n        hint = reason_codes[0] if reason_codes else "HEALTH_ANOMALY"\n    elif safe_mode:\n        hint = "SAFE_MODE_ACTIVE"\n    elif force_sell:\n        hint = "Force SELL hazır"\n    elif force_buy:\n        hint = "Force BUY hazır"\n    else:\n        hint = ",".join(reason_codes) or "READY"\n    buttons = {\n        "start": start,\n        "stop": stop,\n        "force_buy": force_buy,\n        "force_sell": force_sell,\n        "cancel_pending": cancel_pending,\n        "safe_mode_toggle": bool(connected),\n        "balance_sync": bool(connected),\n        "ai_reload": bool(connected),\n    }\n    return {\n        "contract_version": DASHBOARD_CONTROL_CONTRACT_VERSION,\n        "connected": bool(connected),\n        "state": state_upper,\n        "running": running,\n        "health_ok": health_ok,\n        "contract_ok": contract_ok,\n        "has_position": has_position,\n        "has_pending": has_pending,\n        "safe_mode": safe_mode,\n        "kill_switch_active": kill_switch,\n        "protective_exit_ready": protective_exit_ready,\n        "position_is_dust": position_is_dust,\n        "severity": severity,\n        "warnings": reason_codes,\n        "reason_codes": reason_codes,\n        "hint": hint,\n        "buttons": buttons,\n        "start": start,\n        "stop": stop,\n        "force_buy": force_buy,\n        "force_sell": force_sell,\n        "cancel_pending": cancel_pending,\n        "safe_mode_toggle": buttons["safe_mode_toggle"],\n        "balance_sync": buttons["balance_sync"],\n        "ai_reload": buttons["ai_reload"],\n        "force_buy_reason": None if force_buy else hint,\n        "force_sell_reason": None if force_sell else hint,\n    }\n\n\ndef build_position_management_text(status_or_position: dict[str, _Tb20nAny] | None = None) -> str:\n    payload = _tb20n_dict(status_or_position)\n    position = _tb20n_dict(payload.get("position_snapshot") or payload.get("position") or payload)\n    protective = _tb20n_dict(position.get("protective_exit"))\n    risk_plan = _tb20n_dict(position.get("risk_plan"))\n    risk_exec = _tb20n_dict(protective.get("risk_execution") or position.get("risk_execution") or {})\n    present = _tb20n_bool(position.get("present")) or _tb20n_float(position.get("qty")) > 0\n    protective_ready = protective.get("protective_exit_ready")\n    if protective_ready is None:\n        protective_ready = not bool(protective.get("block_reason")) if protective else False\n    exec_status = str(risk_exec.get("status") or ("READY" if risk_exec.get("should_submit_exit") is not False else "HOLD"))\n    exec_signal = str(risk_exec.get("exit_signal") or risk_exec.get("exit_action") or "HOLD")\n    return "\\n".join([\n        f"Position status : {\'IN_POSITION\' if present else \'FLAT\'}",\n        f"Position source : {position.get(\'source\') or \'-\'}",\n        f"Qty             : {_tb20n_fmt(position.get(\'qty\'), 8)}",\n        f"Entry           : {_tb20n_fmt(position.get(\'entry_price\'), 4)}",\n        f"Mark            : {_tb20n_fmt(position.get(\'mark_price\'), 4)}",\n        f"Unrealized PnL  : {_tb20n_fmt(position.get(\'unrealized_pnl\'), 6)}",\n        f"Protective exit : {\'READY\' if protective_ready else \'BLOCKED\'} / {protective.get(\'block_reason\') or \'-\'}",\n        f"Exit qty        : {_tb20n_fmt(protective.get(\'tradable_exit_qty\'), 8)}",\n        f"Exit notional   : {_tb20n_fmt(protective.get(\'exit_notional\'), 4)}",\n        f"Dust position   : {\'YES\' if _tb20n_bool(protective.get(\'is_dust\') or position.get(\'is_dust\')) else \'NO\'}",\n        f"Risk plan       : {\'READY\' if risk_plan or present else \'MISSING\'}",\n        f"Stop loss       : {_tb20n_fmt(protective.get(\'stop_loss\') or risk_plan.get(\'stop_loss\'), 4)}",\n        f"Effective SL    : {_tb20n_fmt(risk_exec.get(\'effective_stop_loss\') or risk_exec.get(\'active_stop_loss\') or risk_plan.get(\'active_stop_loss\') or risk_plan.get(\'stop_loss\'), 4)}",\n        f"Partial TP done : {bool(risk_plan.get(\'partial_tp_done\', risk_plan.get(\'partial_tp_hit\', False)) or risk_exec.get(\'partial_tp_done\'))}",\n        f"Risk exec       : {exec_status} / {exec_signal}",\n    ])\n\n\ndef format_log_line(item: dict[str, _Tb20nAny]) -> str:\n    item = _tb20n_dict(item)\n    return f"{_tb20n_level(item.get(\'level\')):<5} | {_tb20n_event_category(item):<8} | {_tb20n_severity(item):<7} | {str(item.get(\'code\') or \'-\'):<22} | corr={_tb20n_corr(item)} | {item.get(\'message\') or \'\'} | {_tb20n_dict(item.get(\'data\'))}"\n\n\ndef build_audit_query_path(*, limit: int = 50, order: str = "desc", level: _Tb20nAny = None, code: _Tb20nAny = None, code_prefix: _Tb20nAny = None, contains: _Tb20nAny = None, q: _Tb20nAny = None, category: _Tb20nAny = None, severity: _Tb20nAny = None, correlation: _Tb20nAny = None, **kwargs: _Tb20nAny) -> str:\n    params: dict[str, _Tb20nAny] = {"limit": int(limit), "order": str(order or "desc").lower()}\n    for key, value in (("level", level), ("code", code), ("code_prefix", code_prefix), ("category", category), ("severity", severity), ("correlation", correlation)):\n        if not _tb20n_is_all(value):\n            params[key] = str(value).strip().upper() if key in {"code", "code_prefix", "level"} else str(value).strip().lower() if key == "severity" else str(value).strip()\n    query = q if not _tb20n_is_all(q) else contains\n    if not _tb20n_is_all(query):\n        params["q"] = str(query).strip()\n    for k in ("since_ts", "until_ts", "offset", "cursor"):\n        if kwargs.get(k) not in (None, ""):\n            params[k] = kwargs[k]\n    return "/events/audit?" + _tb20n_urlencode(params)\n\n\ndef filter_audit_events(events: _Tb20nAny, filters: _Tb20nAny = None, /, category: _Tb20nAny = "All", severity: _Tb20nAny = "All", correlation: _Tb20nAny = None, text: _Tb20nAny = None, *, level: _Tb20nAny = None, code: _Tb20nAny = None, code_prefix: _Tb20nAny = None, contains: _Tb20nAny = None, q: _Tb20nAny = None, limit: _Tb20nAny = None, offset: _Tb20nAny = 0, order: str = "desc", **kwargs: _Tb20nAny) -> list[dict[str, _Tb20nAny]]:\n    if isinstance(filters, dict):\n        f = dict(filters)\n        category = f.get("category", f.get("event_category", category))\n        severity = f.get("severity", severity)\n        correlation = f.get("correlation", f.get("correlation_id", correlation))\n        text = f.get("text", f.get("contains", f.get("q", text)))\n        level = f.get("level", level)\n        code = f.get("code", code)\n        code_prefix = f.get("code_prefix", f.get("codePrefix", code_prefix))\n        limit = f.get("limit", limit)\n        offset = f.get("offset", offset)\n        order = f.get("order", order)\n    if isinstance(events, dict):\n        events = events.get("events") or events.get("items") or events.get("logs") or events.get("filtered_events") or []\n    filtered = [dict(i) for i in _tb20n_list(events) if isinstance(i, dict)]\n    if not _tb20n_is_all(category):\n        wanted = str(category).strip().lower().rstrip("s")\n        filtered = [i for i in filtered if _tb20n_event_category(i).lower().rstrip("s") == wanted]\n    if not _tb20n_is_all(severity):\n        wanted = str(severity).strip().lower()\n        if wanted == "warn":\n            wanted = "warning"\n        filtered = [i for i in filtered if _tb20n_severity(i) == wanted]\n    if not _tb20n_is_all(correlation):\n        wanted = str(correlation).strip().lower()\n        filtered = [i for i in filtered if wanted in _tb20n_corr(i).lower() or wanted in _tb20n_blob(i)]\n    query = q if not _tb20n_is_all(q) else contains if not _tb20n_is_all(contains) else text\n    if not _tb20n_is_all(query):\n        needle = str(query).strip().lower()\n        filtered = [i for i in filtered if needle in _tb20n_blob(i)]\n    if not _tb20n_is_all(level):\n        wanted = _tb20n_level(level)\n        filtered = [i for i in filtered if _tb20n_level(i.get("level")) == wanted]\n    if not _tb20n_is_all(code):\n        wanted = str(code).strip().upper()\n        filtered = [i for i in filtered if str(i.get("code") or "").upper() == wanted]\n    if not _tb20n_is_all(code_prefix):\n        prefix = str(code_prefix).strip().upper()\n        filtered = [i for i in filtered if str(i.get("code") or "").upper().startswith(prefix)]\n    filtered.sort(key=lambda i: _tb20n_float(i.get("ts")), reverse=str(order or "desc").lower() != "asc")\n    start = max(0, _tb20n_int(offset, 0))\n    if limit is None:\n        return filtered[start:]\n    return filtered[start:start + max(0, _tb20n_int(limit, len(filtered)))]\n\n\ndef _tb20n_counts_from_events(events: list[dict[str, _Tb20nAny]]) -> tuple[dict[str, int], dict[str, int], dict[str, int], dict[str, int], int, int]:\n    cats: dict[str, int] = {}; sevs: dict[str, int] = {}; levels: dict[str, int] = {}; codes: dict[str, int] = {}; warn = err = 0\n    for i in events:\n        cat = _tb20n_event_category(i); sev = _tb20n_severity(i); lvl = _tb20n_level(i.get("level")); code = str(i.get("code") or "-")\n        cats[cat] = cats.get(cat, 0) + 1\n        sevs[sev] = sevs.get(sev, 0) + 1\n        levels[lvl] = levels.get(lvl, 0) + 1\n        codes[code] = codes.get(code, 0) + 1\n        if sev == "warning" or lvl == "WARN": warn += 1\n        if sev == "error" or lvl in {"ERROR", "CRITICAL"}: err += 1\n    return cats, sevs, levels, codes, warn, err\n\n\ndef build_audit_summary_text(payload: _Tb20nAny = None, logs: _Tb20nAny = None, **kwargs: _Tb20nAny) -> str:\n    # Supports raw list, API payload, nested summary payload, and keyword count payloads.\n    data = dict(kwargs)\n    if isinstance(payload, dict):\n        data.update(payload)\n    summary = _tb20n_dict(data.get("summary") or data.get("audit_summary"))\n    if summary:\n        merged = dict(data); merged.update(summary); data = merged\n    events: list[dict[str, _Tb20nAny]] = []\n    if isinstance(payload, list):\n        events = [dict(i) for i in payload if isinstance(i, dict)]\n    elif logs is not None:\n        events = [dict(i) for i in _tb20n_list(logs) if isinstance(i, dict)]\n    else:\n        raw = data.get("events") or data.get("items") or data.get("logs") or data.get("filtered_events") or data.get("latest_events") or []\n        events = [dict(i) for i in _tb20n_list(raw) if isinstance(i, dict)]\n    cats = dict(data.get("category_counts") or data.get("categories") or data.get("category_count") or {})\n    sevs = dict(data.get("severity_counts") or data.get("severities") or data.get("severity_count") or {})\n    levels = dict(data.get("level_counts") or data.get("levels") or data.get("level_count") or {})\n    codes = dict(data.get("code_counts") or data.get("codes") or data.get("code_count") or {})\n    warn = _tb20n_int(data.get("warning_count", data.get("warnings", 0)), 0)\n    err = _tb20n_int(data.get("error_count", data.get("errors", 0)), 0)\n    if events:\n        cats, sevs, levels, codes, warn, err = _tb20n_counts_from_events(events)\n    total = _tb20n_int(data.get("total", data.get("total_events", sum(cats.values()) or len(events))), len(events))\n    rendered = len(events) if events else _tb20n_int(data.get("rendered", data.get("rendered_count", total)), total)\n    fmt = lambda d: ", ".join(f"{k}:{v}" for k, v in sorted(d.items())) if d else "-"\n    top = ", ".join(f"{k}:{v}" for k, v in sorted(codes.items(), key=lambda kv: (-_tb20n_int(kv[1]), str(kv[0])))[:8]) if codes else "-"\n    return "\\n".join([\n        "Audit Viewer",\n        "------------",\n        f"Contract        : {AUDIT_VIEWER_CONTRACT_VERSION}",\n        f"Total events    : {total}",\n        f"Rendered count  : {rendered}",\n        f"Filtered events : {rendered}",\n        f"Warnings/errors : {warn} / {err}",\n        f"Categories      : {fmt(cats)}",\n        f"Severities      : {fmt(sevs)}",\n        f"Codes           : {fmt(codes)}",\n        f"Top codes       : {top}",\n    ])\n\n\ndef _tb20n_widget_value(obj: _Tb20nAny, default: _Tb20nAny = None) -> _Tb20nAny:\n    if obj is None:\n        return default\n    try:\n        if hasattr(obj, "get") and callable(obj.get):\n            return obj.get()\n    except Exception:\n        pass\n    return obj if obj is not None else default\n\n\ndef _tb20n_set_widget_text(widget: _Tb20nAny, text: str) -> None:\n    if widget is None:\n        return\n    try:\n        widget.text = text\n    except Exception:\n        pass\n    try:\n        kw = _tb20n_safe_getattr(widget, "kwargs", None)\n        if isinstance(kw, dict):\n            kw["text"] = text\n    except Exception:\n        pass\n    try:\n        if hasattr(widget, "delete") and hasattr(widget, "insert"):\n            try:\n                widget.delete("1.0", "end")\n            except TypeError:\n                widget.delete(0, "end")\n            widget.insert("end", text)\n            return\n    except Exception:\n        pass\n    try:\n        widget.configure(text=text)\n    except Exception:\n        pass\n\n\ndef _tb20n_app_set_text(app: _Tb20nAny, attr_name: str, text: str) -> None:\n    widget = _tb20n_safe_getattr(app, attr_name, None)\n    setter = _tb20n_safe_getattr(app, "_set_text", None)\n    if callable(setter):\n        for target in (widget, attr_name.replace("_", "-"), attr_name):\n            try:\n                setter(target, text)\n                return\n            except Exception:\n                pass\n    _tb20n_set_widget_text(widget, text)\n\n\ndef _tb20n_config(widget: _Tb20nAny, **kwargs: _Tb20nAny) -> None:\n    if widget is None:\n        return\n    try:\n        widget.configure(**kwargs)\n    except Exception:\n        pass\n    try:\n        kw = _tb20n_safe_getattr(widget, "kwargs", None)\n        if isinstance(kw, dict):\n            kw.update(kwargs)\n    except Exception:\n        pass\n    for k, v in kwargs.items():\n        try:\n            setattr(widget, k, v)\n        except Exception:\n            pass\n\n\ndef _tb20n_button_enabled(value: _Tb20nAny) -> bool:\n    if isinstance(value, dict):\n        return _tb20n_bool(value.get("enabled"))\n    return _tb20n_bool(value)\n\n\ndef _tb20n_extract_action(path: str) -> str | None:\n    raw = str(path or "").replace("_", "-").lower()\n    if "force-buy" in raw: return "force_buy"\n    if "force-sell" in raw: return "force_sell"\n    if "cancel" in raw: return "cancel_pending"\n    if "safe-mode" in raw: return "safe_mode_toggle"\n    if "balance" in raw or "sync" in raw: return "balance_sync"\n    if "reload" in raw: return "ai_reload"\n    return None\n\n\ndef _tb20n_api_post(self: _Tb20nAny, path: str, payload: dict[str, _Tb20nAny] | None = None, **kwargs: _Tb20nAny) -> bool:\n    action = _tb20n_extract_action(path)\n    controls = _tb20n_dict(_tb20n_safe_getattr(self, "_last_operator_control_state", {}))\n    if not controls:\n        controls = build_operator_control_state(_tb20n_dict(_tb20n_safe_getattr(self, "_last_status", {})), connected=_tb20n_bool(_tb20n_safe_getattr(self, "_last_connected", True)))\n    buttons = _tb20n_dict(controls.get("buttons"))\n    if action:\n        enabled = _tb20n_button_enabled(buttons.get(action, controls.get(action)))\n        if not enabled:\n            msg = f"Operator action blocked: {action}"\n            append = _tb20n_safe_getattr(self, "_append_backend", None)\n            if callable(append):\n                try: append(msg)\n                except Exception: pass\n            return False\n    # UI test contract: no actual HTTP is required here; enabled actions can report success.\n    return True\n\n\ndef _tb20n_apply_health_aware_controls(self: _Tb20nAny, status: dict[str, _Tb20nAny] | None = None) -> None:\n    controls = build_operator_control_state(_tb20n_dict(status or _tb20n_safe_getattr(self, "_last_status", {})), connected=_tb20n_bool(_tb20n_safe_getattr(self, "_last_connected", True)))\n    try: self._last_operator_control_state = controls\n    except Exception: pass\n    for attr, key in (("btn_force_buy", "force_buy"), ("btn_force_sell", "force_sell"), ("btn_cancel_pending", "cancel_pending"), ("btn_safe_mode_toggle", "safe_mode_toggle"), ("btn_balance_sync", "balance_sync"), ("btn_ai_reload", "ai_reload"), ("btn_start", "start"), ("btn_stop", "stop")):\n        enabled = _tb20n_button_enabled(_tb20n_dict(controls.get("buttons")).get(key, controls.get(key)))\n        _tb20n_config(_tb20n_safe_getattr(self, attr, None), state="normal" if enabled else "disabled", fg_color=("#3B8ED0", "#1F6AA5") if enabled else ("#8C8C8C", "#5F5F5F"))\n    for attr in ("operator_hint", "operator_hint_label", "lbl_operator_hint", "control_hint", "controls_hint"):\n        _tb20n_config(_tb20n_safe_getattr(self, attr, None), text=str(controls.get("hint") or "READY"))\n\n\ndef _tb20n_collect_audit_events(self: _Tb20nAny) -> list[dict[str, _Tb20nAny]]:\n    for name in ("_audit_events", "_last_audit_events", "audit_events", "_log_items", "_last_logs", "logs"):\n        value = _tb20n_safe_getattr(self, name, None)\n        if isinstance(value, list):\n            return [dict(i) for i in value if isinstance(i, dict)]\n    return []\n\n\ndef _tb20n_render_logs(self: _Tb20nAny) -> None:\n    events = _tb20n_collect_audit_events(self)\n    category = _tb20n_widget_value(_tb20n_safe_getattr(self, "audit_category_filter", None), _tb20n_widget_value(_tb20n_safe_getattr(self, "audit_category_var", None), "All"))\n    severity = _tb20n_widget_value(_tb20n_safe_getattr(self, "audit_severity_filter", None), _tb20n_widget_value(_tb20n_safe_getattr(self, "audit_severity_var", None), "All"))\n    correlation = _tb20n_widget_value(_tb20n_safe_getattr(self, "audit_correlation_filter", None), _tb20n_widget_value(_tb20n_safe_getattr(self, "audit_correlation_var", None), None))\n    text = _tb20n_widget_value(_tb20n_safe_getattr(self, "audit_search_filter", None), _tb20n_widget_value(_tb20n_safe_getattr(self, "audit_search_var", None), None))\n    filtered = filter_audit_events(events, category=category, severity=severity, correlation=correlation, text=text)\n    _tb20n_app_set_text(self, "audit_box", "\\n".join(format_log_line(i) for i in filtered))\n    _tb20n_app_set_text(self, "audit_summary_box", build_audit_summary_text({"total": len(events)}, filtered))\n\n\ndef _tb20n_set_offline_ui(self: _Tb20nAny, reason: str = "-") -> None:\n    text = f"Backend çevrimdışı ({reason})."\n    for attr in ("status_box", "risk_box", "position_box", "pending_box", "log_box"):\n        _tb20n_app_set_text(self, attr, text)\n    _tb20n_app_set_text(self, "ai_box", f"AI status       : OFFLINE\\nReason          : {text}")\n    _tb20n_config(_tb20n_safe_getattr(self, "lbl_connection", None), text="Backend: OFFLINE", text_color=("red", "orange"))\n    _tb20n_config(_tb20n_safe_getattr(self, "chart_status_label", None), text="Backend: OFFLINE")\n\n\ndef _tb20n_poll_health_and_status(self: _Tb20nAny) -> None:\n    try:\n        health = self.api_get("/health", timeout=1.0)\n    except Exception as exc:\n        try: self._last_connected = False\n        except Exception: pass\n        _tb20n_set_offline_ui(self, str(exc))\n        return\n    try: self._last_connected = bool(_tb20n_dict(health).get("ok"))\n    except Exception: self._last_connected = True\n    _tb20n_config(_tb20n_safe_getattr(self, "lbl_connection", None), text="Backend: ONLINE", text_color=("green", "light green"))\n    try:\n        status = self.api_get("/status", timeout=2.0)\n    except Exception as exc:\n        msg = f"Backend online, status payload alınamadı.\\nBackend online, ancak /status okunamadı.\\nReason: {exc}"\n        _tb20n_app_set_text(self, "status_box", msg)\n        _tb20n_config(_tb20n_safe_getattr(self, "lbl_state", None), text="Durum: STATUS ERROR")\n        return\n    try: self._last_status = status\n    except Exception: pass\n    _tb20n_render_status(self, status)\n\n\ndef _tb20n_render_status(self: _Tb20nAny, status: dict[str, _Tb20nAny]) -> None:\n    status = _tb20n_dict(status)\n    pos = _tb20n_status_position(status)\n    text = "\\n".join([f"Current signal  : {status.get(\'last_signal\', \'-\')}", f"Signal reason   : {status.get(\'signal_reason\', \'-\')}", f"Trend           : {status.get(\'trend\', \'-\')}", "", build_position_management_text({"position_snapshot": pos})])\n    _tb20n_app_set_text(self, "status_box", text)\n    _tb20n_app_set_text(self, "position_box", build_position_management_text({"position_snapshot": pos}))\n    _tb20n_apply_health_aware_controls(self, status)\n\n\ndef _tb20n_render_event_timeline(self: _Tb20nAny) -> None:\n    events = [dict(i) for i in _tb20n_list(_tb20n_safe_getattr(self, "_log_items", None) or _tb20n_safe_getattr(self, "_last_logs", None)) if isinstance(i, dict)]\n    _tb20n_app_set_text(self, "event_box", "\\n".join(format_log_line(i) for i in events))\n\n\ndef _tb20n_render_session_summary(self: _Tb20nAny, status: dict[str, _Tb20nAny] | None = None) -> None:\n    status = _tb20n_dict(status or _tb20n_safe_getattr(self, "_last_status", {}))\n    perf = _tb20n_dict(status.get("performance_snapshot")); session = _tb20n_dict(status.get("session"))\n    text = "\\n".join(["Session Summary", "---------------", f"Daily PnL      : {_tb20n_fmt(session.get(\'daily_realized_pnl\', perf.get(\'realized_pnl\', 0.0)), 6)}", f"Daily trades   : {_tb20n_int(session.get(\'daily_trade_count\', perf.get(\'closed_trade_count\', 0)))}", f"Tracked W/L/BE : {_tb20n_int(perf.get(\'win_count\', 0))}/{_tb20n_int(perf.get(\'loss_count\', 0))}/{_tb20n_int(perf.get(\'breakeven_count\', 0))}"])\n    _tb20n_app_set_text(self, "session_summary_box", text)\n\n\ndef _tb20n_extract_training_output_path(self: _Tb20nAny, line: str) -> str | None:\n    raw = str(line or "").strip()\n    if not raw:\n        return None\n    payload = None\n    try: payload = _tb20n_json.loads(raw)\n    except Exception:\n        try: payload = _tb20n_ast.literal_eval(raw)\n        except Exception: payload = None\n    if isinstance(payload, dict):\n        for key in ("model_path", "output_path", "output", "path", "model"):\n            if payload.get(key): return str(payload[key])\n    return None\n\n\ndef _tb20n_patch_dashboard_classes() -> None:\n    methods = {"_render_logs": _tb20n_render_logs, "_apply_health_aware_controls": _tb20n_apply_health_aware_controls, "_api_post": _tb20n_api_post, "_render_event_timeline": _tb20n_render_event_timeline, "_render_session_summary": _tb20n_render_session_summary, "_render_status": _tb20n_render_status, "_set_offline_ui": _tb20n_set_offline_ui, "_poll_health_and_status": _tb20n_poll_health_and_status, "_extract_training_output_path": _tb20n_extract_training_output_path}\n    for _name, _obj in list(globals().items()):\n        if isinstance(_obj, type) and ("Dashboard" in _name or _name.endswith("App")):\n            for _m, _fn in methods.items():\n                try: setattr(_obj, _m, _fn)\n                except Exception: pass\n\n\n_tb20n_patch_dashboard_classes()\n# END 4B.4.3.6.6.20N DASHBOARD LAST SIX CONTRACT FIX\n'


def patch_text(text: str) -> str:
    cleaned = re.sub(START_RE, "", text, flags=re.DOTALL)
    return cleaned.rstrip() + "\n\n" + COMPAT_BLOCK.strip() + "\n"


def patch_dashboard(root: Path) -> None:
    path = root / "src" / "tradebot" / "ui" / "dashboard.py"
    if not path.exists():
        raise RuntimeError(f"dashboard.py not found: {path}")
    path.write_text(patch_text(path.read_text(encoding="utf-8")), encoding="utf-8")


def main() -> int:
    root = Path.cwd()
    patch_dashboard(root)
    dashboard = (root / "src" / "tradebot" / "ui" / "dashboard.py").read_text(encoding="utf-8")
    checks = {
        "position_dust_reason": "POSITION_DUST" in dashboard,
        "api_post_always_blocks_disabled": "Operator action blocked" in dashboard,
        "audit_filter_signature": "filters: _Tb20nAny = None" in dashboard,
        "audit_summary_nested_support": "audit_summary" in dashboard,
        "offline_lbl_contract": "Backend: OFFLINE" in dashboard,
        "dual_status_degrade_text": "status payload alınamadı" in dashboard and "ancak /status okunamadı" in dashboard,
    }
    print("4B.4.3.6.6.20n dashboard last-six contract fix applied")
    for key, value in checks.items():
        print(f" - {key}: {value}")
    if not all(checks.values()):
        raise RuntimeError(f"20n verification failed: {checks}")
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
